#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int l=1, r=N;
        int first=1;
        while(l<r){
            if(!first) printf(" "); first=0; printf("%d",r);
            printf(" %d",l);
            r--; l++;
        }
        if(l==r){
            if(!first) printf(" ");
            printf("%d",l);
        }
        if(T) printf("\n");
    }
    return 0;
}

