#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        int l=1, r=N;
        bool first=true;
        while(l<r){
            if(!first) cout<<' ';
            cout<<r<<' '<<l;
            first=false;
            --r; ++l;
        }
        if(l==r){
            if(!first) cout<<' ';
            cout<<l;
        }
        if(T) cout<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            int l = 1, r = N;
            boolean first = true;
            while (l < r) {
                if (!first) out.append(' ');
                out.append(r).append(' ').append(l);
                first = false;
                r--; l++;
            }
            if (l == r) {
                if (!first) out.append(' ');
                out.append(l);
            }
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

