const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(input[idx++]);
  let l = 1, r = N;
  let parts = [];
  while (l < r) {
    parts.push(String(r));
    parts.push(String(l));
    r--; l++;
  }
  if (l === r) parts.push(String(l));
  outputs.push(parts.join(' '));
}
